10	        return view('connectors.index',compact('connectors'));
11	    }
12	    public function connect(Request $request, int $connector) {
13	        $c=\Illuminate\Support\Facades\DB::table('connectors')->find($connector);
14	        // Store encrypted config
15	        ConnectorConfiguration::updateOrCreate(['connector_id'=>$connector],['credentials'=>encrypt(json_encode($request->except('_token'))),'settings'=>[]]);
16	        \Illuminate\Support\Facades\DB::table('connectors')->where('id',$connector)->update(['status'=>'connected']);
17	        return back()->with('success','Connector configured.');
