2	namespace App\Http\Controllers;
3	use App\Models\Report; use App\Models\User; use App\Models\Assessment; use App\Models\Risk; use App\Models\Document; use App\Models\ControlActivity;
4	use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Maatwebsite\Excel\Facades\Excel;
5	
6	class ReportController extends Controller {
7	    public function index() { $reports=Report::with('creator')->latest()->paginate(25); return view('reports.index',compact('reports')); }
8	    public function generate(Request $request) {
9	        $request->validate(['type'=>'required|in:user_activity,assessment_status,compliance_dashboard,document_inventory,control_activities,risk_register','name'=>'required|string|max:255']);
10	        $report=Report::create(['name'=>$request->name,'type'=>$request->type,'filters'=>$request->filters??null,'created_by'=>Auth::id()]);
11	        return redirect()->route('reports.download',$report);
12	    }
13	    public function download(Report $report) {
14	        // Generate based on type - simplified export
15	        $headers=['Content-Type'=>'text/csv','Content-Disposition'=>'attachment; filename="'.$report->name.'.csv"'];
16	        $callback=function() use ($report) {
17	            $h=fopen('php://output','w');
18	            fputcsv($h,['Report: '.$report->name,'Generated: '.now()->toDateTimeString()]);
19	            fputcsv($h,[]);
20	            switch($report->type) {
21	                case 'user_activity': fputcsv($h,['Name','Email','Role','Last Login']);
22	                    foreach(User::with('roles')->get() as $u) fputcsv($h,[$u->full_name,$u->email,$u->getRoleNames()->first()??'—',$u->last_login_at?->format('Y-m-d H:i')??'Never']);
23	                    break;
24	                case 'assessment_status': fputcsv($h,['Name','Framework','Status','Completion %']);
25	                    foreach(Assessment::with('framework')->get() as $a) fputcsv($h,[$a->name,$a->framework->name,$a->status,$a->completion_percentage]);
26	                    break;
27	                case 'risk_register': fputcsv($h,['Title','Category','Status','Severity','Owner']);
28	                    foreach(Risk::with('owner')->get() as $r) fputcsv($h,[$r->title,$r->category,$r->status,$r->inherent_severity,$r->owner->full_name??'—']);
29	                    break;
30	                default: fputcsv($h,['No data for this report type.']);
31	            }
32	            fclose($h);
33	        };
34	        return response()->stream($callback,200,$headers);
35	    }
36	    public function destroy(Report $report) { $report->delete(); return redirect()->route('reports.index')->with('success','Report deleted.'); }
37	}
