2	namespace App\Http\Controllers;
3	use App\Models\Questionnaire; use App\Models\QuestionnaireTemplate; use App\Models\Vendor;
4	use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Str;
5	
6	class QuestionnaireController extends Controller {
7	    public function index() { $questionnaires=Questionnaire::with(['vendor','template'])->latest()->paginate(25); return view('questionnaires.index',compact('questionnaires')); }
8	    public function create() { $templates=QuestionnaireTemplate::where('status','active')->get(); $vendors=Vendor::where('status','active')->get(); return view('questionnaires.create',compact('templates','vendors')); }
9	    public function store(Request $request) {
10	        $data=$request->validate(['name'=>'required|string|max:255','questionnaire_template_id'=>'required|exists:questionnaire_templates,id','vendor_id'=>'required|exists:vendors,id','due_date'=>'nullable|date']);
11	        Questionnaire::create(array_merge($data,['created_by'=>Auth::id(),'response_token'=>Str::uuid()]));
12	        return redirect()->route('questionnaires.index')->with('success','Questionnaire created.');
13	    }
14	    public function show(Questionnaire $questionnaire) { $questionnaire->load(['vendor','template','creator']); return view('questionnaires.show',compact('questionnaire')); }
15	    public function edit(Questionnaire $questionnaire) { $templates=QuestionnaireTemplate::where('status','active')->get(); $vendors=Vendor::where('status','active')->get(); return view('questionnaires.edit',compact('questionnaire','templates','vendors')); }
16	    public function update(Request $request, Questionnaire $questionnaire) { $questionnaire->update($request->only('name','due_date')); return redirect()->route('questionnaires.show',$questionnaire)->with('success','Updated.'); }
17	    public function destroy(Questionnaire $questionnaire) { $questionnaire->delete(); return redirect()->route('questionnaires.index')->with('success','Deleted.'); }
18	    public function send(Questionnaire $questionnaire) {
19	        $questionnaire->update(['status'=>'sent','sent_date'=>now()]);
20	        // TODO: send email to vendor primary contact
21	        return back()->with('success','Questionnaire sent to vendor.');
22	    }
23	    public function resend(Questionnaire $questionnaire) { return $this->send($questionnaire); }
24	    public function publicShow(string $token) {
25	        $q=Questionnaire::where('response_token',$token)->with(['vendor','template'])->firstOrFail();
26	        if($q->status==='completed') return view('questionnaires.completed');
27	        $q->update(['status'=>'in_progress']);
28	        return view('questionnaires.public',compact('q'));
29	    }
30	    public function publicSubmit(Request $request, string $token) {
31	        $q=Questionnaire::where('response_token',$token)->firstOrFail();
32	        $q->update(['responses'=>$request->responses,'status'=>'completed','completed_date'=>now()]);
33	        return view('questionnaires.thank-you');
34	    }
35	}
