5	
6	class UserController extends Controller {
7	    public function index() { $users=User::with('roles')->latest()->paginate(25); return view('users.index',compact('users')); }
8	    public function create() { $roles=Role::all(); return view('users.create',compact('roles')); }
9	    public function store(Request $request) {
10	        $data=$request->validate(['first_name'=>'required|string|max:255','last_name'=>'required|string|max:255','email'=>'required|email|unique:users','password'=>'required|min:8|confirmed','role'=>'required|exists:roles,name']);
11	        $user=User::create(['first_name'=>$data['first_name'],'last_name'=>$data['last_name'],'email'=>$data['email'],'password'=>Hash::make($data['password']),'partner'=>$request->partner]);
12	        $user->assignRole($data['role']);
13	        return redirect()->route('users.index')->with('success','User created.');
14	    }
15	    public function show(User $user) { return view('users.show',compact('user')); }
16	    public function edit(User $user) { $roles=Role::all(); return view('users.edit',compact('user','roles')); }
17	    public function update(Request $request, User $user) {
18	        $data=$request->validate(['first_name'=>'required|string|max:255','last_name'=>'required|string|max:255','email'=>'required|email|unique:users,email,'.$user->id,'role'=>'required|exists:roles,name']);
19	        $user->update($request->only('first_name','last_name','email','partner'));
20	        $user->syncRoles([$data['role']]);
21	        if($request->filled('password')) { $request->validate(['password'=>'min:8|confirmed']); $user->update(['password'=>Hash::make($request->password)]); }
22	        return redirect()->route('users.index')->with('success','User updated.');
23	    }
24	    public function destroy(User $user) { $user->delete(); return redirect()->route('users.index')->with('success','User deleted.'); }
25	    public function toggleActive(User $user) { $user->update(['is_active'=>!$user->is_active]); return back()->with('success','User status updated.'); }
26	    public function bulkImport(Request $request) { return back()->with('error','Bulk import not yet implemented.'); }
27	}
