12	    use SoftDeletes, LogsActivity;
13	
14	    protected $fillable = [
15	        'subcontrol_id', 'title', 'description', 'risk_owner_id', 'status', 'category',
16	        'date_identified', 'response_due_date', 'response_plan',
17	        'inherent_likelihood', 'inherent_impact', 'residual_likelihood', 'residual_impact',
18	        'is_key_risk', 'risk_response_type', 'notes',
19	        'annual_loss_expectancy', 'budget_allocated', 'tags',
20	    ];
21	
22	    protected $casts = [
23	        'date_identified'      => 'date',
24	        'response_due_date'    => 'date',
25	        'is_key_risk'          => 'boolean',
26	        'tags'                 => 'array',
27	        'annual_loss_expectancy' => 'decimal:2',
28	        'budget_allocated'     => 'decimal:2',
29	    ];
30	
31	    protected static array $likelihoodValues = [
32	        'rare' => 1, 'unlikely' => 2, 'possible' => 3, 'likely' => 4, 'almost_certain' => 5,
33	    ];
34	
35	    protected static array $impactValues = [
36	        'negligible' => 1, 'minor' => 2, 'moderate' => 3, 'significant' => 4, 'severe' => 5,
37	    ];
38	
39	    public function getActivitylogOptions(): LogOptions
40	    {
