64	    public function getInherentScoreAttribute(): int
65	    {
66	        return (self::$likelihoodValues[$this->inherent_likelihood] ?? 1)
67	             * (self::$impactValues[$this->inherent_impact] ?? 1);
68	    }
69	
70	    public function getResidualScoreAttribute(): ?int
71	    {
72	        if (!$this->residual_likelihood || !$this->residual_impact) return null;
73	        return (self::$likelihoodValues[$this->residual_likelihood] ?? 1)
74	             * (self::$impactValues[$this->residual_impact] ?? 1);
75	    }
76	
77	    public function getInherentSeverityAttribute(): string
78	    {
79	        return self::scoreToSeverity($this->inherent_score);
80	    }
81	
82	    public function getResidualSeverityAttribute(): ?string
83	    {
84	        $score = $this->residual_score;
85	        return $score ? self::scoreToSeverity($score) : null;
86	    }
87	
88	    public static function scoreToSeverity(int $score): string
89	    {
90	        if ($score <= 4)  return 'low';
91	        if ($score <= 9)  return 'medium';
92	        if ($score <= 14) return 'high';
93	        return 'critical';
94	    }
95	}
