2	namespace App\Http\Controllers;
3	use Illuminate\Http\Request; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Storage;
4	
5	class SettingsController extends Controller {
6	    public function index() {
7	        $branding=DB::table('branding')->first();
8	        $settings=DB::table('settings')->pluck('value','key');
9	        return view('settings.index',compact('branding','settings'));
10	    }
11	    public function update(Request $request) {
12	        foreach($request->except(['_token','_method']) as $key=>$value) {
13	            DB::table('settings')->updateOrInsert(['key'=>$key],['value'=>$value,'updated_at'=>now()]);
14	        }
15	        return back()->with('success','Settings saved.');
16	    }
17	    public function updateBranding(Request $request) {
18	        $data=$request->validate(['organization_name'=>'required|string|max:255','primary_color'=>'required|string','secondary_color'=>'required|string','accent_color'=>'required|string','timezone'=>'required|string','date_format'=>'required|string','currency'=>'required|string']);
19	        DB::table('branding')->updateOrInsert([],array_merge($data,['updated_at'=>now()]));
20	        return back()->with('success','Branding updated.');
21	    }
22	    public function uploadLogo(Request $request) {
23	        $request->validate(['logo'=>'required|image|max:2048']);
24	        $path=$request->file('logo')->store('logos','public');
25	        DB::table('branding')->update(['logo_path'=>$path,'updated_at'=>now()]);
26	        return back()->with('success','Logo updated.');
27	    }
28	}
